# ${queryName} — Catalog Service products query (fast PDP/PLP data)
query ${queryName}($skus: [String!]!) {
  products(skus: $skus) {
    sku
    name
    ... on SimpleProductView {
      price { final { amount { value currency } } }
    }
    images(roles: ["thumbnail"]) { url label }
  }
}

{
  "event": "${eventType}",
  "_note": "XDM field map for ${eventType}. Left = Commerce event field, right = XDM path. Types must match the XDM schema in your AEP sandbox.",
  "mapping": {
    "commerce.productListItems": "productListItems",
    "commerce.cart.cartID": "commerce.cart.cartID",
    "identityMap": "identityMap"
  }
}

# ${queryName} — Live Search productSearch (AI-powered, Adobe Sensei)
query ${queryName}($phrase: String!, $pageSize: Int = 12) {
  productSearch(phrase: $phrase, page_size: $pageSize) {
    total_count
    items {
      product { name sku }
      productView { ... on SimpleProductView { price { final { amount { value currency } } } } }
    }
    facets { title attribute buckets { title __typename } }
  }
}
